  // Make request to self
  const req = http.request({
    hostname: 'localhost',
    port: port,
    path: '/',
    method: 'GET'
  }, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      server.close();
    });
  });
  
